    "has_test_set": False,
    "has_judge_prompt": False,
    "ci_runs_evals": False,
    "tracks_eval_history": False,
    "eval_count_per_feature": 0,
}

def eval_readiness(team):
    score = 0
    if team.get("has_test_set"):
        score += 25
    if team.get("has_judge_prompt"):
        score += 15
    if team.get("ci_runs_evals"):
        score += 25
    if team.get("tracks_eval_history"):
        score += 15
    if team.get("eval_count_per_feature", 0) >= 20:
        score += 20
    if score >= 80:
        verdict = "eval-mature"
    elif score >= 50:
        verdict = "eval-aware"
    elif score >= 20:
        verdict = "eval-curious"
    else:
        verdict = "vibes era"
    return {"score": score, "verdict": verdict}

print(f"EvalMatureCo: {eval_readiness(eval_mature_co)}")
print(f"VibeCo:       {eval_readiness(vibe_co)}")

teams = [
    {"name": "CursorClone",     "has_test_set": True,  "has_judge_prompt": True,  "ci_runs_evals": True,  "tracks_eval_history": True,  "eval_count_per_feature": 80},
    {"name": "SeriesBAI",       "has_test_set": True,  "has_judge_prompt": True,  "ci_runs_evals": True,  "tracks_eval_history": False, "eval_count_per_feature": 30},
    {"name": "SeedAI",          "has_test_set": True,  "has_judge_prompt": False, "ci_runs_evals": False, "tracks_eval_history": False, "eval_count_per_feature": 10},
    {"name": "ConsultingShop",  "has_test_set": True,  "has_judge_prompt": True,  "ci_runs_evals": False, "tracks_eval_history": False, "eval_count_per_feature": 5},
    {"name": "PromptShopCo",    "has_test_set": False, "has_judge_prompt": False, "ci_runs_evals": False, "tracks_eval_history": False, "eval_count_per_feature": 0},
]

def score_team(t):
    s = 0
    if t.get("has_test_set"):
        s += 25
    if t.get("has_judge_prompt"):
        s += 15
    if t.get("ci_runs_evals"):
        s += 25
    if t.get("tracks_eval_history"):
        s += 15
    if t.get("eval_count_per_feature", 0) >= 20:
        s += 20
    return s

def verdict_for(score):
    if score >= 80:
        return "eval-mature"
    if score >= 50:
        return "eval-aware"
    if score >= 20:
        return "eval-curious"
    return "vibes era"

def triage_teams(teams):
    verdicts = {t["name"]: verdict_for(score_team(t)) for t in teams}
    most_at_risk = min(teams, key=score_team)["name"]
    return {"verdicts": verdicts, "most_at_risk": most_at_risk}

result = triage_teams(teams)
print(f"verdicts: {result['verdicts']}")
print(f"most at risk: {result['most_at_risk']}")
